// frontend/authFetch.js
// Dùng thay cho fetch() trong tất cả các component admin.
// Tự động gắn token và redirect về /login nếu server trả 401/403.

export const authFetch = async (url, options = {}) => {
    const token = localStorage.getItem("token");

    const response = await fetch(url, {
        ...options,
        headers: {
            "Content-Type": "application/json",
            ...(options.headers || {}),
            "Authorization": `Bearer ${token}`,
        },
    });

    // Token hết hạn hoặc không có quyền → xóa token và về login
    if (response.status === 401 || response.status === 403) {
        localStorage.removeItem("token");
        localStorage.removeItem("user");
        window.location.href = "/login";
        return null; // Dừng, không xử lý tiếp
    }

    return response;
};
